import type { Metadata } from "next";

const BASE_URL = "https://buywhere.ai";
const API_BASE_URL =
  process.env.NEXT_PUBLIC_API_URL ||
  process.env.NEXT_PUBLIC_BUYWHERE_API_URL ||
  "https://api.buywhere.ai";

export type LandingProduct = {
  id: string;
  name: string;
  price: number | null;
  currency: string;
  merchant: string;
  imageUrl: string | null;
  href: string;
  brand: string | null;
  category: string | null;
};

type SearchApiItem = {
  id: number | string;
  name?: string | null;
  title?: string | null;
  price?: number | string | null;
  currency?: string | null;
  source?: string | null;
  merchant?: string | null;
  image_url?: string | null;
  url?: string | null;
  buy_url?: string | null;
  affiliate_url?: string | null;
  brand?: string | null;
  category?: string | null;
};

type SearchApiResponse = {
  items?: SearchApiItem[];
  results?: SearchApiItem[];
};

type ComparisonRow = Record<string, string>;

type Highlight = {
  title: string;
  body: string;
};

type Faq = {
  question: string;
  answer: string;
};

type Cta = {
  title: string;
  body: string;
  href: string;
  label: string;
};

export type SeoLandingPageConfig = {
  slug: string;
  title: string;
  description: string;
  heroEyebrow: string;
  heroTitle: string;
  heroBody: string;
  canonicalPath: string;
  country: "US" | "SG";
  currency: "USD" | "SGD";
  locale: "en_US" | "en_SG";
  searchQuery: string;
  refreshedLabel: string;
  productSectionTitle: string;
  comparisonSectionTitle: string;
  comparisonColumns: string[];
  comparisonRows: ComparisonRow[];
  highlightSectionTitle: string;
  highlights: Highlight[];
  adviceSectionTitle: string;
  advicePoints: string[];
  faqSectionTitle: string;
  faqs: Faq[];
  shopperCta: Cta;
  developerCta: Cta;
  fallbackProducts: LandingProduct[];
};

function formatMerchantName(value?: string | null) {
  if (!value) return "BuyWhere seller";
  return value
    .replace(/[_-]+/g, " ")
    .replace(/\b\w/g, (char) => char.toUpperCase());
}

function normalizeProduct(item: SearchApiItem, fallbackCurrency: string): LandingProduct {
  const numericPrice =
    typeof item.price === "number"
      ? item.price
      : typeof item.price === "string" && item.price.trim()
        ? Number(item.price)
        : null;

  return {
    id: String(item.id),
    name: item.name || item.title || "Untitled product",
    price: Number.isFinite(numericPrice) ? numericPrice : null,
    currency: item.currency || fallbackCurrency,
    merchant: formatMerchantName(item.merchant || item.source),
    imageUrl: item.image_url || null,
    href: item.affiliate_url || item.buy_url || item.url || "#",
    brand: item.brand || null,
    category: item.category || null,
  };
}

export async function getSeoLandingProducts(config: SeoLandingPageConfig): Promise<LandingProduct[]> {
  try {
    const params = new URLSearchParams({
      q: config.searchQuery,
      country: config.country,
      limit: "8",
    });

    const response = await fetch(`${API_BASE_URL}/v1/products/search?${params.toString()}`, {
      headers: {
        Accept: "application/json",
      },
      next: { revalidate: 60 * 60 * 4 },
    });

    if (!response.ok) {
      throw new Error(`Search request failed with ${response.status}`);
    }

    const data = (await response.json()) as SearchApiResponse;
    const items = data.items || data.results || [];

    if (!Array.isArray(items) || items.length === 0) {
      throw new Error("Search response was empty");
    }

    return items.map((item) => normalizeProduct(item, config.currency)).slice(0, 8);
  } catch {
    return config.fallbackProducts;
  }
}

export function buildSeoLandingMetadata(config: SeoLandingPageConfig): Metadata {
  const canonical = `${BASE_URL}${config.canonicalPath}`;

  return {
    title: config.title,
    description: config.description,
    alternates: {
      canonical,
    },
    openGraph: {
      title: config.title,
      description: config.description,
      url: canonical,
      type: "article",
      locale: config.locale,
      siteName: "BuyWhere",
      images: [
        {
          url: "/assets/img/og-image.png",
          width: 1200,
          height: 630,
          alt: config.title,
        },
      ],
    },
    twitter: {
      card: "summary_large_image",
      title: config.title,
      description: config.description,
      site: "@buywhere",
      creator: "@buywhere",
    },
  };
}

export function buildSeoLandingSchema(config: SeoLandingPageConfig, products: LandingProduct[]) {
  const canonical = `${BASE_URL}${config.canonicalPath}`;

  return {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "BreadcrumbList",
        "@id": `${BASE_URL}/#breadcrumb`,
        itemListElement: [
          {
            "@type": "ListItem",
            position: 1,
            name: "Home",
            item: BASE_URL,
          },
          {
            "@type": "ListItem",
            position: 2,
            name: config.heroTitle,
            item: canonical,
          },
        ],
      },
      {
        "@type": "CollectionPage",
        "@id": `${canonical}#collection`,
        name: config.heroTitle,
        description: config.description,
        url: canonical,
        mainEntityOfPage: canonical,
        isPartOf: {
          "@type": "WebSite",
          "@id": `${BASE_URL}/#website`,
          name: "BuyWhere",
          url: BASE_URL,
        },
        about: {
          "@type": "Thing",
          name: config.searchQuery,
        },
        mainEntity: {
          "@type": "ItemList",
          name: config.productSectionTitle,
          itemListElement: products.map((product, index) => ({
            "@type": "ListItem",
            position: index + 1,
            url: product.href,
            item: {
              "@type": "Product",
              name: product.name,
              brand: product.brand
                ? {
                    "@type": "Brand",
                    name: product.brand,
                  }
                : undefined,
              image: product.imageUrl || undefined,
              category: product.category || undefined,
              offers:
                product.price !== null
                  ? {
                      "@type": "Offer",
                      price: product.price,
                      priceCurrency: product.currency,
                      availability: "https://schema.org/InStock",
                      seller: {
                        "@type": "Organization",
                        "@id": `${BASE_URL}/#organization`,
                        name: product.merchant,
                      },
                      url: product.href,
                    }
                  : undefined,
            },
          })),
        },
      },
      {
        "@type": "FAQPage",
        "@id": `${canonical}#faq`,
        mainEntityOfPage: canonical,
        mainEntity: config.faqs.map((faq) => ({
          "@type": "Question",
          name: faq.question,
          acceptedAnswer: {
            "@type": "Answer",
            text: faq.answer,
          },
        })),
      },
    ],
  };
}

